    # pid = ('storage', dtype_cls, key, location, numel)
    typ = pid[0]
    assert typ=='storage'
    dtype = pid[1]
    key = pid[2]
    numel = pid[4]
    return Storage(key, dtype)

import io
class Unp(pickle.Unpickler):
    def persistent_load(self, pid):
        return persistent_load(pid)
    def find_class(self, mod, name):
        # return placeholder callables
        if name=='_rebuild_tensor_v2':
            def f(storage, storage_offset, size, stride, requires_grad, backward_hooks, *a):
                return ('TENSOR', storage.key, size, stride, storage_offset)
            return f
        if name in ('FloatStorage','LongStorage','IntStorage'):
            return name
        if name=='OrderedDict':
            from collections import OrderedDict
            return OrderedDict
        try:
            return super().find_class(mod,name)
        except Exception:
            return lambda *a,**k: (mod,name)
    def load_reduce(self):
        super().load_reduce()

data=z.read('simple_mnist/data.pkl')
obj=Unp(io.BytesIO(data)).load()
for k,v in obj.items():
