#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <vector>
#include <string>
#include "cJSON.h"
#include "lodepng.h"

static std::vector<float> getArray(cJSON* root, const char* name) {
    cJSON* obj = cJSON_GetObjectItemCaseSensitive(root, name);
    if (!obj) { fprintf(stderr, "missing %s\n", name); exit(1); }
    cJSON* data = cJSON_GetObjectItemCaseSensitive(obj, "data");
    if (!data) { fprintf(stderr, "missing data for %s\n", name); exit(1); }
    std::vector<float> v;
    cJSON* e;
    cJSON_ArrayForEach(e, data) v.push_back((float)e->valuedouble);
    return v;
}

static std::vector<float> linear(const std::vector<float>& x, const std::vector<float>& w,
                                 const std::vector<float>& b, int in_f, int out_f) {
    std::vector<float> out(out_f);
    for (int i = 0; i < out_f; ++i) {
        float s = b[i];
        const float* wr = &w[(size_t)i * in_f];
        for (int j = 0; j < in_f; ++j) s += x[j] * wr[j];
        out[i] = s;
    }
    return out;
}

static void relu(std::vector<float>& x) {
    for (float& v : x) if (v < 0) v = 0;
}

int main(int argc, char** argv) {
    if (argc != 3) { fprintf(stderr, "usage: %s weights.json image.png\n", argv[0]); return 1; }

    // Load weights JSON
    FILE* f = fopen(argv[1], "rb");
    if (!f) { fprintf(stderr, "cannot open %s\n", argv[1]); return 1; }
    fseek(f, 0, SEEK_END); long len = ftell(f); fseek(f, 0, SEEK_SET);
    std::string buf(len, '\0');
    if (fread(&buf[0], 1, len, f) != (size_t)len) { fclose(f); return 1; }
    fclose(f);
    cJSON* root = cJSON_Parse(buf.c_str());
    if (!root) { fprintf(stderr, "json parse error\n"); return 1; }

    std::vector<float> w0 = getArray(root, "input_layer.weight");
    std::vector<float> b0 = getArray(root, "input_layer.bias");
    std::vector<float> w1 = getArray(root, "hidden_layer.weight");
    std::vector<float> b1 = getArray(root, "hidden_layer.bias");
    std::vector<float> w2 = getArray(root, "output_layer.weight");
    std::vector<float> b2 = getArray(root, "output_layer.bias");
    cJSON_Delete(root);

    int hidden = (int)b0.size();
    int in_dim = (int)(w0.size() / hidden);
    int num_classes = (int)b2.size();

    // Load PNG as grayscale 8-bit
    std::vector<unsigned char> img;
    unsigned iw, ih;
    unsigned err = lodepng::decode(img, iw, ih, argv[2], LCT_GREY, 8);
    if (err) { fprintf(stderr, "png decode error: %s\n", lodepng_error_text(err)); return 1; }

    std::vector<float> x((size_t)iw * ih);
    for (size_t i = 0; i < x.size(); ++i) x[i] = img[i] / 255.0f;
    if ((int)x.size() != in_dim) {
        fprintf(stderr, "image size %zu != model input %d\n", x.size(), in_dim);
        return 1;
    }

    std::vector<float> h = linear(x, w0, b0, in_dim, hidden); relu(h);
    h = linear(h, w1, b1, hidden, hidden); relu(h);
    std::vector<float> o = linear(h, w2, b2, hidden, num_classes);

    int pred = 0;
    for (int i = 1; i < num_classes; ++i) if (o[i] > o[pred]) pred = i;

    printf("%d\n", pred);
    return 0;
}

